sys_script_fix.script:
/**
 * Fix Script / Background Script:
 * Copy u_ucm_id -> u_ucmid_legacy for customer_account records
 * without triggering business rules, workflows, or auditing.
 *
 * Safe for large volumes; includes dry-run and progress logging.
 */

(function() {
    var TABLE = 'customer_account';
    var SOURCE_FIELD = 'u_ucm_id';
    var TARGET_FIELD = 'u_ucmid_legacy';
    var BATCH_LOG_EVERY = 1000;   // log progress every N processed records
    var SLEEP_MS = 50;            // tiny pause to keep node healthy during long runs
    var DRY_RUN = false;          // set true to preview counts without updating

    var processed = 0;
    var candidates = 0;
    var updated = 0;
    var skipped_equal = 0;
    var skipped_empty_source = 0;
    var errors = 0;

    // Pre-scan query: only fetch records where SOURCE_FIELD is not empty
    var gr = new GlideRecord(TABLE);
    gr.setWorkflow(false);       // disable business rules/workflows/engines
    gr.autoSysFields(false);     // don't touch sys fields
    gr.addQuery("u_account_category=ban^u_ucm_idISNOTEMPTY^u_ucmid_legacy=NULL^NQu_account_category=ban^u_account_numberISNOTEMPTY^u_acc_number_mdm2ISEMPTY"); // exclude blank strings
    gr.query();

    gs.info('[FixScript] Starting copy from ' + SOURCE_FIELD + ' to ' + TARGET_FIELD + ' on table ' + TABLE);

    while (gr.next()) {
        processed++;



        candidates++; // would be updated

        if (!DRY_RUN) {
            try {
                gr.setValue('u_ucmid_legacy', gr.getValue('u_ucm_id'));
				gr.setValue('u_acc_number_mdm2',gr.getValue('u_account_number'));
                gr.update();
                updated++;
            } catch (e) {
                errors++;
                gs.error('[FixScript] Update failed for sys_id=' + gr.getUniqueValue() + ' error=' + e);
            }
        }

        if (processed % BATCH_LOG_EVERY === 0) {
            gs.info('[FixScript] Progress: processed=' + processed +
                    ' candidates=' + candidates + ' updated=' + updated +
                    ' skipped_equal=' + skipped_equal +
                    ' skipped_empty_source=' + skipped_empty_source +
                    ' errors=' + errors);
            gs.sleep(SLEEP_MS);
        }
    }

    gs.info('[FixScript] Completed. ' +
            'processed=' + processed +
            ' candidates=' + candidates +
            ' updated=' + updated +
            ' skipped_equal=' + skipped_equal +
            ' skipped_empty_source=' + skipped_empty_source +
            ' errors=' + errors +
            (DRY_RUN ? ' (DRY RUN: no writes performed)' : ''));
})();
